func:
if (Buffer.isBuffer(msg.payload)) return null;
if (typeof msg.payload !== 'string') return null;
let d;
try { d = JSON.parse(msg.payload); }
catch (e) { return null; }
msg.payload = d;
if (d.heartbeat)         return [null, msg, null];
if (d.power_result)      return [null, null, msg];
if (d.op_status !== undefined) return [msg, null, null];
return null;

const d = msg.payload;
if (!d) return null;
const pwrMap    = { L: 'Low',    M: 'Middle', H: 'Maximum' };
const pwrMaxMap = { L: 500,      M: 1000,     H: 1500      };
if (d.model_id === '20K') {
  pwrMaxMap.L = 700; pwrMaxMap.M = 1400; pwrMaxMap.H = 2000;
}
msg.payload = {
  model:     d.model_id || '—',
  mode:      d.op_status === 'Stby' ? 'Standby' : 'Operate',
  rxtx:      d.tx_status === 'TX'   ? 'TRANSMIT' : 'RECEIVE',
  bank:      '—',
  input:     d.input    || '—',
  band:      (d.band    || '—').toUpperCase(),
  txant:     d.tx_antenna || '—',
  rxant:     '—',
  pwrlvl:    pwrMap[d.p_level] || d.p_level || '—',
  pwr:       parseFloat(d.p_out)   || 0,
  pwrMax:    pwrMaxMap[d.p_level]  || 1500,
  atuswr:    parseFloat(d.swr)     || 1,
  antswr:    parseFloat(d.aswr)    || 1,
  vpa:       parseFloat(d.voltage) || 0,
  ipa:       parseFloat(d.drain)   || 0,
  tempUpper: parseFloat(d.pa_temp)          || 0,
  tempLower: parseFloat(d.pa_temp_lower)    || 0,
  tempComb:  parseFloat(d.pa_temp_combiner) || 0,
  warnings:  d.warnings && d.warnings.trim() ? d.warnings : 'No Warnings',
  alarms:    d.error    && d.error.trim()   ? d.error    : 'No Alarms',
  usb:       true,
  sync:      true
};
return msg;

const d = msg.payload;
if (!d) return null;
msg.payload = { usb: d.serial === 'up', sync: d.serial === 'up' };
return msg;
